/**
 * Debounce a function call.
 * @param {(value: unknown) => void} fn
 * @param {number} waitMs
 * @returns {{ call: (value: unknown) => void, cancel: () => void }}
 */
export function debounce(fn, waitMs) {
  let timerId;

  const cancel = () => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
  };

  const call = (value) => {
    cancel();
    timerId = setTimeout(() => {
      timerId = undefined;
      fn(value);
    }, waitMs);
  };

  return { call, cancel };
}
